#!/usr/bin/env python3
"""
HD995 — Client-side notification clean sweep. Removes ALL client-side email
notification code now that every path (task, note, ticket reply/assign, RFC,
Contact Client) is handled server-side by NotificationService (slices 1-5).

Removes the three _notify methods + callers, CreateTicket._notifyContactClient +
caller, the RFC client notify calls, PageBase._sendNotificationEmail /
_determineNotificationType, TicketLoader's window.TicketEmailData publish, and
deletes wwwroot/js/Components/Emails/Emails.js plus its _Layout script tag.

Each removal is an exact verified byte block (asserted to appear exactly once).
After removal all 8 touched JS files pass `node --check` with zero remaining
references to the removed functions.

ASSUMES the full notification stack is merged (email-routing-fix, contactclient,
server slices 1-5). Idempotent. Usage: python3 apply_notification_cleanup.py [root]
"""

import base64
import os
import sys

ROOT = sys.argv[1] if len(sys.argv) > 1 else '.'

# (key, relative_path, base64_block_to_remove)
REMOVALS = [
    ('ticketsave_method', 'wwwroot/js/Ticket/Features/TicketSave.js', ''),
    ('ticketsave_caller', 'wwwroot/js/Ticket/Features/TicketSave.js', 'CiAgICAgICAgICAgIGF3YWl0IFNhdmUuX25vdGlmeShkYXRhLCBwYXlsb2FkLlRpY2tldElEKTsK'),
    ('messagepanel_method', 'wwwroot/js/Components/Messages/MessagePanel.js', ''),
    ('messagepanel_caller', 'wwwroot/js/Components/Messages/MessagePanel.js', 'CiAgICAgICAgICAgIC8vIE5vdGlmeSB0aGUgY2xpZW50IHRoYXQgYSB2aXNpYmxlIHVwZGF0ZSB3YXMgcG9zdGVkLgogICAgICAgICAgICBfbm90aWZ5KCk7'),
    ('tasks_method', 'wwwroot/js/Tasks/Features/Tasks.js', ''),
    ('tasks_caller', 'wwwroot/js/Tasks/Features/Tasks.js', 'ICAgICAgICAgICAgX25vdGlmeVRhc2soZGF0YSk7Cg=='),
    ('createticket_method', 'wwwroot/js/Ticket/Pages/CreateTicket.js', ''),
    ('createticket_caller', 'wwwroot/js/Ticket/Pages/CreateTicket.js', 'ICAgICAgICBpZiAoY29udGFjdENsaWVudCkgew0KICAgICAgICAgICAgYXdhaXQgdGhpcy5fbm90aWZ5Q29udGFjdENsaWVudChuZXdUaWNrZXRJZCwgY29udGFjdENsaWVudCk7DQogICAgICAgIH0NCg0K'),
    ('rfcsave_block', 'wwwroot/js/RFC/Features/RFCSave.js', 'ICAgICAgICBpZiAodmlzaWJpbGl0eSAmJiAhYXV0b1NhdmUpIHsKICAgICAgICAgICAgLy8gX3NlbmROb3RpZmljYXRpb25FbWFpbCBpbmhlcml0ZWQgZnJvbSBUaWNrZXRCYXNlCiAgICAgICAgICAgIHRoaXMuX3NlbmROb3RpZmljYXRpb25FbWFpbCgnUkZDJywgZGF0YVswXSwgcmZjSWQgPz8gZGF0YVsxXSk7CiAgICAgICAgfQo='),
    ('createrfc_block', 'wwwroot/js/RFC/Pages/CreateRFC.js', ''),
    ('pagebase_methods', 'wwwroot/js/Shared/PageBase.js', ''),
    ('ticketloader_block', 'wwwroot/js/Ticket/Features/TicketLoader.js', ''),
]

LAYOUT = 'Views/Shared/_Layout.cshtml'
EMAILS = 'wwwroot/js/Components/Emails/Emails.js'


def main():
    print("HD995 — client-side notification clean sweep")
    print(f"  repo root: {os.path.abspath(ROOT)}")

    for key, rel, b64 in REMOVALS:
        path = os.path.join(ROOT, rel)
        if not os.path.exists(path):
            print(f"  [error] missing {path}")
            sys.exit(1)
        blk = base64.b64decode(b64)
        data = open(path, 'rb').read()
        c = data.count(blk)
        if c == 0:
            print(f"  [skip] {key}: already removed")
            continue
        if c != 1:
            print(f"  [error] {key}: block matched {c} times (expected 1); aborting")
            sys.exit(1)
        open(path, 'wb').write(data.replace(blk, b'', 1))
        print(f"  [write] removed {key}")

    # remove the _Layout script tag (CRLF or LF)
    lay = os.path.join(ROOT, LAYOUT)
    d = open(lay, 'rb').read()
    tag = b'    <script src="~/js/Components/Emails/Emails.js" asp-append-version="true"></script>\r\n'
    if tag not in d:
        tag = tag.replace(b'\r\n', b'\n')
    if tag in d:
        if d.count(tag) != 1:
            print("  [error] _Layout Emails.js tag not unique; aborting")
            sys.exit(1)
        open(lay, 'wb').write(d.replace(tag, b'', 1))
        print("  [write] removed _Layout Emails.js script tag")
    else:
        print("  [skip] _Layout Emails.js tag: already removed")

    # delete Emails.js
    em = os.path.join(ROOT, EMAILS)
    if os.path.exists(em):
        os.remove(em)
        print("  [write] deleted Emails.js")
    else:
        print("  [skip] Emails.js: already deleted")

    print("Done.")
    print("  [note] stage deletions with `git add -A` (Emails.js is removed).")
    print("  [note] run `dotnet build` + a JS smoke test; no client mail code remains.")


if __name__ == '__main__':
    main()
